import React, { useEffect, useState } from 'react';
import './Admin.css';
import './AdminUsers.css';
import { authFetch } from "./authFetch";

const AdminUsers = () => {
    const [users, setUsers] = useState([]);
    const [search, setSearch] = useState('');

    const loadUsers = async () => {
        const res = await authFetch('http://localhost:5000/api/users');
        if (!res) return;
        const data = await res.json();
        setUsers(res.ok && Array.isArray(data) ? data : []);
    };

    useEffect(() => { loadUsers(); }, []);

    const updateRole = async (id, role_id) => {
        const res = await authFetch(`http://localhost:5000/api/users/${id}/role`, {
            method: 'PUT',
            body: JSON.stringify({ role_id: Number(role_id) })
        });
        if (!res) return;
        if (res.ok) { alert('Cập nhật quyền thành công!'); loadUsers(); }
        else { const err = await res.json(); alert('Lỗi: ' + err.message); }
    };

    const updateStatus = async (id, is_active) => {
        const res = await authFetch(`http://localhost:5000/api/users/${id}/status`, {
            method: 'PUT',
            body: JSON.stringify({ is_active })
        });
        if (!res) return;
        if (res.ok) { alert('Cập nhật trạng thái thành công!'); loadUsers(); }
        else { const err = await res.json(); alert('Lỗi: ' + err.message); }
    };

    const deleteUser = async (id) => {
        if (!window.confirm('Bạn có chắc muốn xóa user này?')) return;
        const res = await authFetch(`http://localhost:5000/api/users/${id}`, { method: 'DELETE' });
        if (!res) return;
        if (res.ok) { alert('Đã xóa người dùng!'); loadUsers(); }
        else { const err = await res.json(); alert('Lỗi: ' + err.message); }
    };

    const filteredUsers = users.filter(u =>
        u.username?.toLowerCase().includes(search.toLowerCase()) ||
        u.email?.toLowerCase().includes(search.toLowerCase())
    );

    return (
        <div className="admin-card">
            <div className="admin-card-header">
                <h2>Quản lý người dùng</h2>
                <input type="text" placeholder="Tìm kiếm user..." className="admin-search"
                    value={search} onChange={(e) => setSearch(e.target.value)} />
            </div>

            <table className="admin-table">
                <thead>
                    <tr>
                        <th>ID</th><th>Tên</th><th>Email</th><th>SĐT</th>
                        <th>Role</th><th>Trạng thái</th><th>Ngày tạo</th><th>Thao tác</th>
                    </tr>
                </thead>
                <tbody>
                    {filteredUsers.map(user => (
                        <tr key={user.user_id}>
                            <td>#{user.user_id}</td>
                            <td>{user.username}</td>
                            <td>{user.email}</td>
                            <td>{user.phone_number}</td>
                            <td>
                                {/* role_id=2 là Admin, role_id=1 là Customer */}
                                <select value={user.role_id}
                                    onChange={e => updateRole(user.user_id, e.target.value)}>
                                    <option value="2">Admin</option>
                                    <option value="1">Customer</option>
                                </select>
                            </td>
                            <td>
                                <button
                                    className={user.is_active ? 'btn-active' : 'btn-block'}
                                    onClick={() => updateStatus(user.user_id, !user.is_active)}>
                                    {user.is_active ? 'Hoạt động' : 'Đã khóa'}
                                </button>
                            </td>
                            <td>{user.created_at ? new Date(user.created_at).toLocaleDateString() : '—'}</td>
                            <td>
                                <button className="btn-delete" onClick={() => deleteUser(user.user_id)}>Xóa</button>
                            </td>
                        </tr>
                    ))}
                </tbody>
            </table>
        </div>
    );
};

export default AdminUsers;
